func formatEvalTime(ns int64) string {
	d := time.Duration(ns)
	if d < time.Microsecond {
		return fmt.Sprintf("%dns", ns)
	}
	if d < time.Millisecond {
		return fmt.Sprintf("%.1fus", float64(ns)/1000)
	}
	return fmt.Sprintf("%.1fms", float64(ns)/1e6)
}

